    16→/**
    17→ * \file
    18→ * \brief C++ API: Region classes (territory containment)
    19→ */
    20→
    21→#include "unicode/region.h"
    22→#include "unicode/utypes.h"
    23→#include "unicode/uobject.h"
    24→#include "unicode/unistr.h"
    25→#include "unicode/ures.h"
    26→#include "unicode/decimfmt.h"
    27→#include "ucln_in.h"
    28→#include "cstring.h"
    29→#include "mutex.h"
    30→#include "uhash.h"
    31→#include "umutex.h"
    32→#include "uresimp.h"
    33→#include "region_impl.h"
    34→
    35→#if !UCONFIG_NO_FORMATTING
    36→
    37→
    38→U_CDECL_BEGIN
    39→
    40→static void U_CALLCONV
    41→deleteRegion(void *obj) {
    42→    delete (icu::Region *)obj;
    43→}
    44→
    45→/**
    46→ * Cleanup callback func
    47→ */
    48→static UBool U_CALLCONV region_cleanup(void)
    49→{
    50→    icu::Region::cleanupRegionData();
    51→
    52→    return TRUE;
    53→}
    54→
    55→U_CDECL_END
    56→
    57→U_NAMESPACE_BEGIN
    58→
    59→static UInitOnce gRegionDataInitOnce = U_INITONCE_INITIALIZER;
    60→static UVector* availableRegions[URGN_LIMIT];
    61→
    62→static UHashtable *regionAliases;
    63→static UHashtable *regionIDMap;
    64→static UHashtable *numericCodeMap;
    65→
    66→static const UChar UNKNOWN_REGION_ID [] = { 0x5A, 0x5A, 0 };  /* "ZZ" */
    67→static const UChar OUTLYING_OCEANIA_REGION_ID [] = { 0x51, 0x4F, 0 };  /* "QO" */
    68→static const UChar WORLD_ID [] = { 0x30, 0x30, 0x31, 0 };  /* "001" */
    69→
    70→UOBJECT_DEFINE_RTTI_IMPLEMENTATION(RegionNameEnumeration)
    71→
    72→/*
    73→ * Initializes the region data from the ICU resource bundles.  The region data
    74→ * contains the basic relationships such as which regions are known, what the numeric
    75→ * codes are, any known aliases, and the territory containment data.
    76→ *
    77→ * If the region data has already loaded, then this method simply returns without doing
    78→ * anything meaningful.
    79→ */
    80→void Region::loadRegionData(UErrorCode &status) {
    81→    LocalPointer<DecimalFormat> df(new DecimalFormat(status));
    82→    if (U_FAILURE(status)) {
    83→        return;
    84→    }
    85→    if (df == NULL) {
    86→        status = U_MEMORY_ALLOCATION_ERROR;
    87→        return;
    88→    }
    89→    df->setParseIntegerOnly(TRUE);
    90→
    91→    regionIDMap = uhash_open(uhash_hashUnicodeString, uhash_compareUnicodeString, NULL, &status);
    92→    if (U_FAILURE(status)) {
    93→        return;
    94→    }
    95→    if (regionIDMap == NULL) {
    96→        status = U_MEMORY_ALLOCATION_ERROR;
    97→        return;
    98→    }
    99→    uhash_setValueDeleter(regionIDMap, deleteRegion);
   100→
   101→    numericCodeMap = uhash_open(uhash_hashLong,uhash_compareLong,NULL,&status);
   102→
   103→    regionAliases = uhash_open(uhash_hashUnicodeString,uhash_compareUnicodeString,NULL,&status);
   104→    if (U_FAILURE(status)) {
   105→        return;
   106→    }
   107→    if (regionAliases == NULL) {
   108→        status = U_MEMORY_ALLOCATION_ERROR;
   109→        return;
   110→    }
   111→    uhash_setKeyDeleter(regionAliases,uprv_deleteUObject);
   112→
   113→    LocalUResourceBundlePointer rb(ures_openDirect(NULL,"metadata",&status));
   114→    LocalUResourceBundlePointer regionCodes(ures_getByKey(rb.getAlias(),"regionCodes",NULL,&status));
   115→    LocalUResourceBundlePointer territoryAlias(ures_getByKey(rb.getAlias(),"territoryAlias",NULL,&status));
   116→
   117→    LocalUResourceBundlePointer rb2(ures_openDirect(NULL,"supplementalData",&status));
   118→    LocalUResourceBundlePointer codeMappings(ures_getByKey(rb2.getAlias(),"codeMappings",NULL,&status));
   119→
   120→    LocalUResourceBundlePointer territoryContainment(ures_getByKey(rb2.getAlias(),"territoryContainment",NULL,&status));
   121→    LocalUResourceBundlePointer worldContainment(ures_getByKey(territoryContainment.getAlias(),"001",NULL,&status));
   122→    LocalUResourceBundlePointer groupingContainment(ures_getByKey(territoryContainment.getAlias(),"grouping",NULL,&status));
   123→
   124→    UVector *continents = new UVector(uprv_deleteUObject, uhash_compareUnicodeString, status);
   125→
   126→    while ( ures_hasNext(worldContainment.getAlias()) ) {
   127→        UnicodeString *continentName = new UnicodeString(ures_getNextUnicodeString(worldContainment.getAlias(),NULL,&status));
   128→        continents->addElement(continentName,status);
   129→    }
   130→
   131→    UVector *groupings = new UVector(uprv_deleteUObject, uhash_compareUnicodeString, status);
   132→    while ( ures_hasNext(groupingContainment.getAlias()) ) {
   133→        UnicodeString *groupingName = new UnicodeString(ures_getNextUnicodeString(groupingContainment.getAlias(),NULL,&status));
   134→        groupings->addElement(groupingName,status);
   135→    }
   136→
   137→    while ( ures_hasNext(regionCodes.getAlias()) ) {
   138→        UnicodeString regionID = ures_getNextUnicodeString(regionCodes.getAlias(), NULL, &status);
   139→        Region *r = new Region();
   140→        r->idStr = regionID;
   141→        r->idStr.extract(0,r->idStr.length(),r->id,sizeof(r->id),US_INV);
   142→        r->type = URGN_TERRITORY; // Only temporary - figure out the real type later once the aliases are known.
   143→
   144→        uhash_put(regionIDMap,(void *)&(r->idStr),(void *)r,&status);
   145→        Formattable result;
   146→        UErrorCode ps = U_ZERO_ERROR;
   147→        df->parse(r->idStr,result,ps);
   148→        if ( U_SUCCESS(ps) ) {
   149→            r->code = result.getLong(); // Convert string to number
   150→            uhash_iput(numericCodeMap,r->code,(void *)r,&status);
   151→            r->type = URGN_SUBCONTINENT;
   152→        } else {
   153→            r->code = -1;
   154→        }
   155→    }
   156→
   157→
   158→    // Process the territory aliases
   159→    while ( ures_hasNext(territoryAlias.getAlias()) ) {
   160→        UResourceBundle *res = ures_getNextResource(territoryAlias.getAlias(),NULL,&status);
   161→        const char *aliasFrom = ures_getKey(res);
   162→        UnicodeString* aliasFromStr = new UnicodeString(aliasFrom, -1, US_INV);
   163→        UnicodeString aliasTo = ures_getUnicodeString(res,&status);
   164→        ures_close(res);
   165→
   166→        Region *aliasToRegion = (Region *) uhash_get(regionIDMap,&aliasTo);
   167→        Region *aliasFromRegion = (Region *)uhash_get(regionIDMap,aliasFromStr);
   168→
   169→        if ( aliasToRegion != NULL && aliasFromRegion == NULL ) { // This is just an alias from some string to a region
   170→            uhash_put(regionAliases,(void *)aliasFromStr, (void *)aliasToRegion,&status);
   171→        } else {
   172→            if ( aliasFromRegion == NULL ) { // Deprecated region code not in the master codes list - so need to create a deprecated region for it.
   173→                aliasFromRegion = new Region();
   174→                aliasFromRegion->idStr.setTo(*aliasFromStr);
   175→                aliasFromRegion->idStr.extract(0,aliasFromRegion->idStr.length(),aliasFromRegion->id,sizeof(aliasFromRegion->id),US_INV);
   176→                uhash_put(regionIDMap,(void *)&(aliasFromRegion->idStr),(void *)aliasFromRegion,&status);
   177→                Formattable result;
   178→                UErrorCode ps = U_ZERO_ERROR;
   179→                df->parse(aliasFromRegion->idStr,result,ps);
   180→                if ( U_SUCCESS(ps) ) {
   181→                    aliasFromRegion->code = result.getLong(); // Convert string to number
   182→                    uhash_iput(numericCodeMap,aliasFromRegion->code,(void *)aliasFromRegion,&status);
   183→                } else {
   184→                    aliasFromRegion->code = -1;
   185→                }
   186→                aliasFromRegion->type = URGN_DEPRECATED;
   187→            } else {
   188→                aliasFromRegion->type = URGN_DEPRECATED;
   189→            }
   190→            delete aliasFromStr;
   191→
   192→            aliasFromRegion->preferredValues = new UVector(uprv_deleteUObject, uhash_compareUnicodeString, status);
   193→            UnicodeString currentRegion;
   194→            currentRegion.remove();
   195→            for (int32_t i = 0 ; i < aliasTo.length() ; i++ ) {
   196→                if ( aliasTo.charAt(i) != 0x0020 ) {
   197→                    currentRegion.append(aliasTo.charAt(i));
   198→                }
   199→                if ( aliasTo.charAt(i) == 0x0020 || i+1 == aliasTo.length() ) {
   200→                    Region *target = (Region *)uhash_get(regionIDMap,(void *)&currentRegion);
   201→                    if (target) {
   202→                        UnicodeString *preferredValue = new UnicodeString(target->idStr);
   203→                        aliasFromRegion->preferredValues->addElement((void *)preferredValue,status);
   204→                    }
   205→                    currentRegion.remove();
   206→                }
   207→            }
   208→        }
   209→    }
   210→
   211→    // Process the code mappings - This will allow us to assign numeric codes to most of the territories.
   212→    while ( ures_hasNext(codeMappings.getAlias()) ) {
   213→        UResourceBundle *mapping = ures_getNextResource(codeMappings.getAlias(),NULL,&status);
   214→        if ( ures_getType(mapping) == URES_ARRAY && ures_getSize(mapping) == 3) {
   215→            UnicodeString codeMappingID = ures_getUnicodeStringByIndex(mapping,0,&status);
   216→            UnicodeString codeMappingNumber = ures_getUnicodeStringByIndex(mapping,1,&status);
   217→            UnicodeString codeMapping3Letter = ures_getUnicodeStringByIndex(mapping,2,&status);
   218→
   219→            Region *r = (Region *)uhash_get(regionIDMap,(void *)&codeMappingID);
   220→            if ( r ) {
   221→                Formattable result;
   222→                UErrorCode ps = U_ZERO_ERROR;
   223→                df->parse(codeMappingNumber,result,ps);
   224→                if ( U_SUCCESS(ps) ) {
   225→                    r->code = result.getLong(); // Convert string to number
   226→                    uhash_iput(numericCodeMap,r->code,(void *)r,&status);
   227→                }
   228→                UnicodeString *code3 = new UnicodeString(codeMapping3Letter);
   229→                uhash_put(regionAliases,(void *)code3, (void *)r,&status);
   230→            }
   231→        }
   232→        ures_close(mapping);
   233→    }
   234→
   235→    // Now fill in the special cases for WORLD, UNKNOWN, CONTINENTS, and GROUPINGS
   236→    Region *r;
   237→	UnicodeString WORLD_ID_STRING(WORLD_ID);
   238→    r = (Region *) uhash_get(regionIDMap,(void *)&WORLD_ID_STRING);
   239→    if ( r ) {
   240→        r->type = URGN_WORLD;
   241→    }
   242→
   243→	UnicodeString UNKNOWN_REGION_ID_STRING(UNKNOWN_REGION_ID);
   244→    r = (Region *) uhash_get(regionIDMap,(void *)&UNKNOWN_REGION_ID_STRING);
   245→    if ( r ) {
   246→        r->type = URGN_UNKNOWN;
   247→    }
   248→
   249→    for ( int32_t i = 0 ; i < continents->size() ; i++ ) {
   250→        r = (Region *) uhash_get(regionIDMap,(void *)continents->elementAt(i));
   251→        if ( r ) {
   252→            r->type = URGN_CONTINENT;
   253→        }
   254→    }
   255→    delete continents;
   256→
   257→    for ( int32_t i = 0 ; i < groupings->size() ; i++ ) {
   258→        r = (Region *) uhash_get(regionIDMap,(void *)groupings->elementAt(i));
   259→        if ( r ) {
   260→            r->type = URGN_GROUPING;
   261→        }
   262→    }
   263→    delete groupings;
   264→
   265→    // Special case: The region code "QO" (Outlying Oceania) is a subcontinent code added by CLDR
   266→    // even though it looks like a territory code.  Need to handle it here.
   267→
   268→	UnicodeString OUTLYING_OCEANIA_REGION_ID_STRING(OUTLYING_OCEANIA_REGION_ID);
   269→    r = (Region *) uhash_get(regionIDMap,(void *)&OUTLYING_OCEANIA_REGION_ID_STRING);
   270→    if ( r ) {
   271→        r->type = URGN_SUBCONTINENT;
   272→    }
   273→
   274→    // Load territory containment info from the supplemental data.
   275→    while ( ures_hasNext(territoryContainment.getAlias()) ) {
   276→        UResourceBundle *mapping = ures_getNextResource(territoryContainment.getAlias(),NULL,&status);
   277→        const char *parent = ures_getKey(mapping);
   278→        if (uprv_strcmp(parent, "containedGroupings") == 0 || uprv_strcmp(parent, "deprecated") == 0) {
   279→            ures_close(mapping);
   280→            continue; // handle new pseudo-parent types added in ICU data per cldrbug 7808; for now just skip.
   281→            // #11232 is to do something useful with these.
   282→        }
   283→        UnicodeString parentStr = UnicodeString(parent, -1 , US_INV);
   284→        Region *parentRegion = (Region *) uhash_get(regionIDMap,(void *)&parentStr);
   285→
   286→        for ( int j = 0 ; j < ures_getSize(mapping); j++ ) {
   287→            UnicodeString child = ures_getUnicodeStringByIndex(mapping,j,&status);
   288→            Region *childRegion = (Region *) uhash_get(regionIDMap,(void *)&child);
   289→            if ( parentRegion != NULL && childRegion != NULL ) {
   290→
   291→                // Add the child region to the set of regions contained by the parent
   292→                if (parentRegion->containedRegions == NULL) {
   293→                    parentRegion->containedRegions = new UVector(uprv_deleteUObject, uhash_compareUnicodeString, status);
   294→                }
   295→
   296→                UnicodeString *childStr = new UnicodeString();
   297→                childStr->fastCopyFrom(childRegion->idStr);
   298→                parentRegion->containedRegions->addElement((void *)childStr,status);
   299→
   300→                // Set the parent region to be the containing region of the child.
   301→                // Regions of type GROUPING can't be set as the parent, since another region
   302→                // such as a SUBCONTINENT, CONTINENT, or WORLD must always be the parent.
   303→                if ( parentRegion->type != URGN_GROUPING) {
   304→                    childRegion->containingRegion = parentRegion;
   305→                }
   306→            }
   307→        }
   308→        ures_close(mapping);
   309→    }
   310→
   311→    // Create the availableRegions lists
   312→    int32_t pos = -1;
   313→    while ( const UHashElement* element = uhash_nextElement(regionIDMap,&pos)) {
   314→        Region *ar = (Region *)element->value.pointer;
   315→        if ( availableRegions[ar->type] == NULL ) {
   316→            availableRegions[ar->type] = new UVector(uprv_deleteUObject, uhash_compareUnicodeString, status);
   317→        }
   318→        UnicodeString *arString = new UnicodeString(ar->idStr);
   319→        availableRegions[ar->type]->addElement((void *)arString,status);
   320→    }
   321→
   322→    ucln_i18n_registerCleanup(UCLN_I18N_REGION, region_cleanup);
   323→}
   324→
   325→void Region::cleanupRegionData() {
   326→    for (int32_t i = 0 ; i < URGN_LIMIT ; i++ ) {
   327→        if ( availableRegions[i] ) {
   328→            delete availableRegions[i];
   329→        }
   330→    }
   331→
   332→    if (regionAliases) {
   333→        uhash_close(regionAliases);
   334→    }
   335→
   336→    if (numericCodeMap) {
   337→        uhash_close(numericCodeMap);
   338→    }
   339→
   340→    if (regionIDMap) {
   341→        uhash_close(regionIDMap);
   342→    }
   343→    gRegionDataInitOnce.reset();
   344→}
   345→
   346→Region::Region ()
   347→        : code(-1),
   348→          type(URGN_UNKNOWN),
   349→          containingRegion(NULL),
   350→          containedRegions(NULL),
   351→          preferredValues(NULL) {
   352→    id[0] = 0;
   353→}
   354→
   355→Region::~Region () {
   356→        if (containedRegions) {
   357→            delete containedRegions;
   358→        }
   359→        if (preferredValues) {
   360→            delete preferredValues;
   361→        }
   362→}
   363→
   364→/**
   365→ * Returns true if the two regions are equal.
   366→ */
   367→UBool
   368→Region::operator==(const Region &that) const {
   369→    return (idStr == that.idStr);
   370→}
   371→
   372→/**
   373→ * Returns true if the two regions are NOT equal; that is, if operator ==() returns false.
   374→ */
   375→UBool
   376→Region::operator!=(const Region &that) const {
   377→        return (idStr != that.idStr);
   378→}
   379→
   380→/**
   381→ * Returns a pointer to a Region using the given region code.  The region code can be either 2-letter ISO code,
   382→ * 3-letter ISO code,  UNM.49 numeric code, or other valid Unicode Region Code as defined by the LDML specification.
   383→ * The identifier will be canonicalized internally using the supplemental metadata as defined in the CLDR.
   384→ * If the region code is NULL or not recognized, the appropriate error code will be set ( U_ILLEGAL_ARGUMENT_ERROR )
   385→ */
   386→const Region* U_EXPORT2
   387→Region::getInstance(const char *region_code, UErrorCode &status) {
   388→
   389→    umtx_initOnce(gRegionDataInitOnce, &loadRegionData, status);
   390→    if (U_FAILURE(status)) {
   391→        return NULL;
   392→    }
   393→
   394→    if ( !region_code ) {
   395→        status = U_ILLEGAL_ARGUMENT_ERROR;
   396→        return NULL;
   397→    }
   398→
   399→    UnicodeString regionCodeString = UnicodeString(region_code, -1, US_INV);
   400→    Region *r = (Region *)uhash_get(regionIDMap,(void *)&regionCodeString);
   401→
   402→    if ( !r ) {
   403→        r = (Region *)uhash_get(regionAliases,(void *)&regionCodeString);
   404→    }
   405→
   406→    if ( !r ) { // Unknown region code
   407→        status = U_ILLEGAL_ARGUMENT_ERROR;
   408→        return NULL;
   409→    }
   410→
   411→    if ( r->type == URGN_DEPRECATED && r->preferredValues->size() == 1) {
   412→        StringEnumeration *pv = r->getPreferredValues();
   413→        pv->reset(status);
   414→        const UnicodeString *ustr = pv->snext(status);
   415→        r = (Region *)uhash_get(regionIDMap,(void *)ustr);
   416→        delete pv;
   417→    }
   418→
   419→    return r;
   420→
   421→}
   422→
   423→/**
   424→ * Returns a pointer to a Region using the given numeric region code. If the numeric region code is not recognized,
   425→ * the appropriate error code will be set ( U_ILLEGAL_ARGUMENT_ERROR ).
   426→ */
   427→const Region* U_EXPORT2
   428→Region::getInstance (int32_t code, UErrorCode &status) {
   429→
   430→    umtx_initOnce(gRegionDataInitOnce, &loadRegionData, status);
   431→    if (U_FAILURE(status)) {
   432→        return NULL;
   433→    }
   434→
   435→    Region *r = (Region *)uhash_iget(numericCodeMap,code);
   436→
   437→    if ( !r ) { // Just in case there's an alias that's numeric, try to find it.
   438→        UErrorCode fs = U_ZERO_ERROR;
   439→        UnicodeString pat = UNICODE_STRING_SIMPLE("00#");
   440→        DecimalFormat *df = new DecimalFormat(pat,fs);
   441→
   442→        UnicodeString id;
   443→        id.remove();
   444→        df->format(code,id);
   445→        delete df;
   446→        r = (Region *)uhash_get(regionAliases,&id);
   447→    }
   448→
   449→    if ( !r ) {
   450→        status = U_ILLEGAL_ARGUMENT_ERROR;
   451→        return NULL;
   452→    }
   453→
   454→    if ( r->type == URGN_DEPRECATED && r->preferredValues->size() == 1) {
   455→        StringEnumeration *pv = r->getPreferredValues();
   456→        pv->reset(status);
   457→        const UnicodeString *ustr = pv->snext(status);
   458→        r = (Region *)uhash_get(regionIDMap,(void *)ustr);
   459→        delete pv;
   460→    }
   461→
   462→    return r;
   463→}
   464→
   465→
   466→/**
   467→ * Returns an enumeration over the IDs of all known regions that match the given type.
   468→ */
   469→StringEnumeration* U_EXPORT2
   470→Region::getAvailable(URegionType type) {
   471→    UErrorCode status = U_ZERO_ERROR;
   472→    umtx_initOnce(gRegionDataInitOnce, &loadRegionData, status);
   473→    if (U_FAILURE(status)) {
   474→        return NULL;
   475→    }
   476→    return new RegionNameEnumeration(availableRegions[type],status);
   477→}
   478→
   479→/**
   480→ * Returns a pointer to the region that contains this region.  Returns NULL if this region is code "001" (World)
   481→ * or "ZZ" (Unknown region). For example, calling this method with region "IT" (Italy) returns the
   482→ * region "039" (Southern Europe).
   483→ */
   484→const Region*
   485→Region::getContainingRegion() const {
   486→    UErrorCode status = U_ZERO_ERROR;
   487→    umtx_initOnce(gRegionDataInitOnce, &loadRegionData, status);
   488→    return containingRegion;
   489→}
   490→
   491→/**
   492→ * Return a pointer to the region that geographically contains this region and matches the given type,
   493→ * moving multiple steps up the containment chain if necessary.  Returns NULL if no containing region can be found
   494→ * that matches the given type. Note: The URegionTypes = "URGN_GROUPING", "URGN_DEPRECATED", or "URGN_UNKNOWN"
   495→ * are not appropriate for use in this API. NULL will be returned in this case. For example, calling this method
   496→ * with region "IT" (Italy) for type "URGN_CONTINENT" returns the region "150" ( Europe ).
   497→ */
   498→const Region*
   499→Region::getContainingRegion(URegionType type) const {
   500→    UErrorCode status = U_ZERO_ERROR;
   501→    umtx_initOnce(gRegionDataInitOnce, &loadRegionData, status);
   502→    if ( containingRegion == NULL ) {
   503→        return NULL;
   504→    }
   505→
   506→    if ( containingRegion->type == type ) {
   507→        return containingRegion;
   508→    } else {
   509→        return containingRegion->getContainingRegion(type);
   510→    }
   511→}
   512→
   513→/**
   514→ * Return an enumeration over the IDs of all the regions that are immediate children of this region in the
   515→ * region hierarchy. These returned regions could be either macro regions, territories, or a mixture of the two,
   516→ * depending on the containment data as defined in CLDR.  This API may return NULL if this region doesn't have
   517→ * any sub-regions. For example, calling this method with region "150" (Europe) returns an enumeration containing
   518→ * the various sub regions of Europe - "039" (Southern Europe) - "151" (Eastern Europe) - "154" (Northern Europe)
   519→ * and "155" (Western Europe).
   520→ */
   521→StringEnumeration*
   522→Region::getContainedRegions() const {
   523→    UErrorCode status = U_ZERO_ERROR;
   524→    umtx_initOnce(gRegionDataInitOnce, &loadRegionData, status);
   525→    return new RegionNameEnumeration(containedRegions,status);
   526→}
   527→
   528→/**
   529→ * Returns an enumeration over the IDs of all the regions that are children of this region anywhere in the region
   530→ * hierarchy and match the given type.  This API may return an empty enumeration if this region doesn't have any
   531→ * sub-regions that match the given type. For example, calling this method with region "150" (Europe) and type
   532→ * "URGN_TERRITORY" returns a set containing all the territories in Europe ( "FR" (France) - "IT" (Italy) - "DE" (Germany) etc. )
   533→ */
   534→StringEnumeration*
   535→Region::getContainedRegions( URegionType type ) const {
   536→    UErrorCode status = U_ZERO_ERROR;
   537→    umtx_initOnce(gRegionDataInitOnce, &loadRegionData, status);
   538→    if (U_FAILURE(status)) {
   539→        return NULL;
   540→    }
   541→
   542→    UVector *result = new UVector(NULL, uhash_compareChars, status);
   543→
   544→    StringEnumeration *cr = getContainedRegions();
   545→
   546→    for ( int32_t i = 0 ; i < cr->count(status) ; i++ ) {
   547→        const char *id = cr->next(NULL,status);
   548→        const Region *r = Region::getInstance(id,status);
   549→        if ( r->getType() == type ) {
   550→            result->addElement((void *)&r->idStr,status);
   551→        } else {
   552→            StringEnumeration *children = r->getContainedRegions(type);
   553→            for ( int32_t j = 0 ; j < children->count(status) ; j++ ) {
   554→                const char *id2 = children->next(NULL,status);
   555→                const Region *r2 = Region::getInstance(id2,status);
   556→                result->addElement((void *)&r2->idStr,status);
   557→            }
   558→            delete children;
   559→        }
   560→    }
   561→    delete cr;
   562→    StringEnumeration* resultEnumeration = new RegionNameEnumeration(result,status);
   563→    delete result;
   564→    return resultEnumeration;
   565→}
   566→
   567→/**
   568→ * Returns true if this region contains the supplied other region anywhere in the region hierarchy.
   569→ */
   570→UBool
   571→Region::contains(const Region &other) const {
   572→    UErrorCode status = U_ZERO_ERROR;
   573→    umtx_initOnce(gRegionDataInitOnce, &loadRegionData, status);
   574→
   575→    if (!containedRegions) {
   576→          return FALSE;
   577→    }
   578→    if (containedRegions->contains((void *)&other.idStr)) {
   579→        return TRUE;
   580→    } else {
   581→        for ( int32_t i = 0 ; i < containedRegions->size() ; i++ ) {
   582→            UnicodeString *crStr = (UnicodeString *)containedRegions->elementAt(i);
   583→            Region *cr = (Region *) uhash_get(regionIDMap,(void *)crStr);
   584→            if ( cr && cr->contains(other) ) {
   585→                return TRUE;
   586→            }
   587→        }
   588→    }
   589→
   590→    return FALSE;
   591→}
   592→
   593→/**
   594→ * For deprecated regions, return an enumeration over the IDs of the regions that are the preferred replacement
   595→ * regions for this region.  Returns NULL for a non-deprecated region.  For example, calling this method with region
   596→ * "SU" (Soviet Union) would return a list of the regions containing "RU" (Russia), "AM" (Armenia), "AZ" (Azerbaijan), etc...
   597→ */
   598→StringEnumeration*
   599→Region::getPreferredValues() const {
   600→    UErrorCode status = U_ZERO_ERROR;
   601→    umtx_initOnce(gRegionDataInitOnce, &loadRegionData, status);
   602→    if ( type == URGN_DEPRECATED ) {
   603→        return new RegionNameEnumeration(preferredValues,status);
   604→    } else {
   605→        return NULL;
   606→    }
   607→}
   608→
   609→
   610→/**
   611→ * Return this region's canonical region code.
   612→ */
   613→const char*
   614→Region::getRegionCode() const {
   615→    return id;
   616→}
   617→
   618→int32_t
   619→Region::getNumericCode() const {
   620→    return code;
   621→}
   622→
   623→/**
   624→ * Returns the region type of this region.
   625→ */
   626→URegionType
   627→Region::getType() const {
   628→    return type;
   629→}
   630→
   631→RegionNameEnumeration::RegionNameEnumeration(UVector *fNameList, UErrorCode& status) {
   632→    pos=0;
   633→    if (fNameList && U_SUCCESS(status)) {
   634→        fRegionNames = new UVector(uprv_deleteUObject, uhash_compareUnicodeString, fNameList->size(),status);
   635→        for ( int32_t i = 0 ; i < fNameList->size() ; i++ ) {
   636→            UnicodeString* this_region_name = (UnicodeString *)fNameList->elementAt(i);
   637→            UnicodeString* new_region_name = new UnicodeString(*this_region_name);
   638→            fRegionNames->addElement((void *)new_region_name,status);
   639→        }
   640→    }
   641→    else {
   642→        fRegionNames = NULL;
   643→    }
   644→}
   645→
   646→const UnicodeString*
   647→RegionNameEnumeration::snext(UErrorCode& status) {
   648→  if (U_FAILURE(status) || (fRegionNames==NULL)) {
   649→    return NULL;
   650→  }
   651→  const UnicodeString* nextStr = (const UnicodeString *)fRegionNames->elementAt(pos);
   652→  if (nextStr!=NULL) {
   653→    pos++;
   654→  }
   655→  return nextStr;
   656→}
   657→
   658→void
   659→RegionNameEnumeration::reset(UErrorCode& /*status*/) {
   660→    pos=0;
   661→}
   662→
   663→int32_t
   664→RegionNameEnumeration::count(UErrorCode& /*status*/) const {
   665→    return (fRegionNames==NULL) ? 0 : fRegionNames->size();
   666→}
   667→
   668→RegionNameEnumeration::~RegionNameEnumeration() {
   669→    delete fRegionNames;
   670→}
   671→
   672→U_NAMESPACE_END
   673→
   674→#endif /* #if !UCONFIG_NO_FORMATTING */
   675→
   676→//eof
   677→

